if command == "add":
    # design.md 2.2 add: check arg count, load, append, save
    if len(sys.argv) < 3:
        print("Usage: python todo.py add \"task content\"")
        return
    content = sys.argv[2]
    todos = load_todos()
    todos.append(content)
    save_todos(todos)

elif command == "list":
    # design.md 2.2 list: load, enumerate with 1-based index, print
    todos = load_todos()
    for i, todo in enumerate(todos, start=1):
        print(f"{i}: {todo}")

elif command == "remove":
    # design.md 2.2 remove: int conversion with try/except, bounds check, pop, save
    try:
        id = int(sys.argv[2])
    except (IndexError, ValueError):
        return
    todos = load_todos()
    if 1 <= id <= len(todos):
        todos.pop(id - 1)
    save_todos(todos)

